{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 일정",
        "decision": "스모크 테스트가 통과하면 공개 릴리스 목표 시각은 금요일 15:00 KST로 정함."
      },
      {
        "topic": "packageName 불일치 처리 원칙",
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토함."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "수요일 공개 릴리스",
        "reason": "스모크 테스트 통과가 선행되어야 해서 채택되지 않음."
      },
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 변경",
        "reason": "논의 후 거절됨."
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일을 내부 스트레치 목표로 삼음",
        "note": "공개 릴리스 확정일이 아니라 내부 목표로만 취급함."
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토",
        "note": "가능하면 목요일까지 검토하자는 의견은 있었지만 담당자가 지정되지 않음."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 타볼 경로는 릴리스를 지연시킬 수 있음."
      },
      {
        "risk": "README 설치 단계가 오래되면 릴리스 노트가 사용자에게 잘못된 인상을 줄 수 있음."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 넣을 것인가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "명시적 확정"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "명시적 확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 smoke 결과가 게시된 뒤 생성된 타볼 경로를 확인한다.",
      "due": "Minjun의 smoke 결과 게시 후",
      "status": "예정",
      "source_certainty": "명시적 확정"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 목요일까지 검토한다.",
      "due": "목요일까지(가능하면)",
      "status": "미배정",
      "source_certainty": "조건부 제안"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 금요일 10:00 KST 스모크 재실행 결과",
      "패키지 설정과 smoke-theme-pack.mjs 계약의 일치 여부",
      "타볼 경로가 기대값과 일치하는지 여부",
      "README 설치 단계가 목요일까지 검토되었는지 여부",
      "최종 릴리스 승인 권한",
      "릴리스 노트에 내부 수요일 스트레치 목표를 넣을지 여부"
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너명",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법적 승인 요건",
      "명시되지 않은 owner",
      "명시되지 않은 deadline"
    ]
  },
  "non_invention_rules": [
    "fixture에 없는 고객, 외부 파트너, 예산, 보안 사고, 장애, 법적 승인 사실은 쓰지 않는다.",
    "owner와 deadline은 명시된 경우만 적고, 미지정이면 임의로 채우지 않는다.",
    "조건부 목표는 조건을 함께 적고 확정 사실처럼 쓰지 않는다.",
    "거절된 제안은 승인된 결정으로 바꾸지 않는다.",
    "내부 스트레치 목표와 공개 릴리스 결정을 구분한다."
  ]
}
